            el.disabled = true;
            el.style.opacity = '0.5';
            el.style.cursor = 'not-allowed';
        }
    });

    // v7.0: 禁用跟踪控制按钮
    var trackButtons = ['btnTrackSidereal', 'btnTrackLunar', 'btnTrackSolar', 'btnTrackOff'];
    trackButtons.forEach(function(id) {
