            // v6.16: 清除 WASM 状态
            if (window.updateWasmStatus) window.updateWasmStatus('disconnected');
            
            // v6.54: 禁用主控台和高级功能
            if (window.disableAllControls) window.disableAllControls('请先连接设备');
            
            apiPost('/api/v1/devices/' + ip + '/disconnect', null).then(function() {
                showToast('success', '设备已断开: ' + ip);
                addLog('info', '设备已断开: ' + ip);
                // --- Clear global window.connectedDevice first, before refresh ---
                if (window.connectedDevice && window.connectedDevice.ip === ip) {
