                    addLog('info', '已清除连接设备状态');
                }
                if (window.updateDeviceStatus) window.updateDeviceStatus();
                refreshDevices();
                refreshPtzDeviceList();
                refreshAdvancedDeviceSelectors();
                var panel = document.getElementById('deviceInfoPanel');
                if (panel) panel.style.display = 'none';
                
                _connectionOperationInProgress = false;
                if (window.setConnectionButtonsEnabled) window.setConnectionButtonsEnabled(true);
            }).catch(function(e) {
                _connectionOperationInProgress = false;
