function wasmLogout() {
    // v5.47: 即使未登录也尝试停止播放，确保画面清理
    try {
        // Stop playback first
        if (g_bPlaying2) {
            WebVideoCtrl.I_Stop();
            g_bPlaying2 = false;
        }
        // Logout from device
        if (g_bLoggedIn2 && g_szDeviceIdentify2) {
            WebVideoCtrl.I_Logout(g_szDeviceIdentify2);
        }
        // v7.0: 不销毁 WASM 容器，只显示灰色覆盖层
        var container = document.getElementById('divPlugin');
        if (container) {
            // 移除旧的覆盖层
            var oldOverlay = document.getElementById('wasm-disconnected-overlay');
            if (oldOverlay) oldOverlay.remove();
            // 创建灰色覆盖层（不破坏 WASM 容器）
            var overlay = document.createElement('div');
            overlay.id = 'wasm-disconnected-overlay';
            overlay.style.cssText = 'position:absolute;top:0;left:0;width:100%;height:100%;background:#0d1117;display:flex;align-items:center;justify-content:center;color:#6e7681;font-size:14px;z-index:10';
            overlay.innerHTML = '设备已断开';
            container.style.position = 'relative';
            container.appendChild(overlay);
        }
    } catch(e) { console.warn('WASM logout error:', e); }
    g_bLoggedIn2 = false;
    g_szDeviceIdentify2 = '';
    g_bPlaying2 = false;
    setLoginStatus('已登出', '#8b949e');
    var loginBtn = document.getElementById('login-btn');
    if (loginBtn) loginBtn.textContent = '登录';

    // v6.12: 更新 WASM 状态
    if (window.updateWasmStatus) window.updateWasmStatus('disconnected');
}

