function loadOsdStatus(deviceIp) {
    // PTZ OSD
    apiGet('/api/v1/ptz/' + deviceIp + '/osd/ptz').then(function(r) {
        if (r && r.success) {
            var enabled = r.enabled || r.data?.enabled || false;
            updatePtzOsdButtons(enabled);
            // 保存到 localStorage
            localStorage.setItem('osd_ptz_' + deviceIp, enabled ? '1' : '0');
        } else {
            // 从 localStorage 读取上次设置
