function wasmLogout() {
    // v7.01: 强制停止播放和登出，不依赖状态变量
    try {
        // v7.01: 强制停止播放，不管状态
        try {
            WebVideoCtrl.I_Stop();
        } catch(stopErr) { 
            console.warn('[WASM] I_Stop error:', stopErr);
        }

        // 强制登出
        if (g_szDeviceIdentify2) {
            try {
                WebVideoCtrl.I_Logout(g_szDeviceIdentify2);
            } catch(logoutErr) {
                console.warn('[WASM] I_Logout error:', logoutErr);
            }
        }

        // v7.01: 确保 WASM 容器存在并添加覆盖层
        var container = document.getElementById('divPlugin');
        if (container) {
            // 移除旧的覆盖层
            var oldOverlay = document.getElementById('wasm-disconnected-overlay');
            if (oldOverlay) oldOverlay.remove();

            // v7.01: 先确保容器可见
            container.style.display = 'block';
            container.style.position = 'relative';

            // 创建灰色覆盖层(使用更高的 z-index 覆盖 WASM 内容)
            var overlay = document.createElement('div');
            overlay.id = 'wasm-disconnected-overlay';
            overlay.style.cssText = 'position:absolute;top:0;left:0;width:100%;height:100%;background:#0d1117;z-index:9999;display:flex;align-items:center;justify-content:center;color:#6e7681;font-size:14px';
            overlay.innerHTML = '设备已断开';
            container.appendChild(overlay);
            console.log('[WASM] Overlay created on disconnect');
        } else {
            console.warn('[WASM] divPlugin container not found');
        }
    } catch(e) { console.warn('WASM logout error:', e); }

    // v7.01: 强制重置状态
    g_bLoggedIn2 = false;
    g_szDeviceIdentify2 = '';
    g_bPlaying2 = false;
    setLoginStatus('已登出', '#8b949e');
    var loginBtn = document.getElementById('login-btn');
    if (loginBtn) loginBtn.textContent = '登录';

    // v6.12: 更新 WASM 状态
    if (window.updateWasmStatus) window.updateWasmStatus('disconnected');
}

