function updateShutterIrisState() {
    var exposureMode = document.getElementById('exposureMode');
    var shutterSelect = document.getElementById('shutterSpeed');
    var irisSelect = document.getElementById('irisLevel');
    var gainSlider = document.getElementById('gainLevel');

    if (!exposureMode || !shutterSelect || !irisSelect) return;

    var isManual = exposureMode.value === 'manual';
    shutterSelect.disabled = !isManual;
    irisSelect.disabled = !isManual;
    if (gainSlider) gainSlider.disabled = !isManual;

    // 禁用时灰色样式
    if (!isManual) {
        shutterSelect.style.opacity = '0.5';
        irisSelect.style.opacity = '0.5';
        if (gainSlider) gainSlider.style.opacity = '0.5';
    } else {
        shutterSelect.style.opacity = '1';
        irisSelect.style.opacity = '1';
        if (gainSlider) gainSlider.style.opacity = '1';
    }
}

